import{_ as t,o as s,c as o,ah as a}from"./chunks/framework.ojwJKwrc.js";const u=JSON.parse('{"title":"Heliodor Macro Benchmark","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks/heliodor.md","filePath":"benchmarks/heliodor.md"}'),i={name:"benchmarks/heliodor.md"};function d(r,e,c,n,l,h){return s(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="heliodor-macro-benchmark" tabindex="-1">Heliodor Macro Benchmark <a class="header-anchor" href="#heliodor-macro-benchmark" aria-label="Permalink to &quot;Heliodor Macro Benchmark&quot;">​</a></h1><p>Heliodor is a large Veryl RISC-V processor project with ignored Linux boot tests. It is useful as a macro benchmark because it stresses project loading, large memories initialized by <code>$readmemh</code>, native testbench scheduling, and long-running sequential simulation.</p><p>This benchmark is not part of normal CI. It checks out Heliodor under <code>target/heliodor/source</code>, installs a missing Veryl CLI into <code>target/heliodor/tools</code>, builds the Celox runner before timing, runs Veryl baselines before Celox by default, and writes a TSV summary plus full logs under <code>target/heliodor/results</code>.</p><h2 id="run" tabindex="-1">Run <a class="header-anchor" href="#run" aria-label="Permalink to &quot;Run&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/run-heliodor-bench.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prepare</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/run-heliodor-bench.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p><code>run</code> is a configurable diagnostic command. It appends measurements, but does not decide whether Celox meets the performance requirement. Use the fixed <code>gate</code> command for that decision.</p><p>By default this runs <code>test_soc_linux_boot</code> with Veryl Cranelift, Veryl cc, then Celox. Celox is timed out after <code>HELIODOR_CELOX_TIMEOUT_MULTIPLIER</code> times the fastest successful Veryl baseline for that test.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HELIODOR_TESTS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;test_soc_linux_boot test_soc_smp_linux_boot_2hart&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HELIODOR_RUNNERS=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;celox veryl-cranelift veryl-cc&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scripts/run-heliodor-bench.sh </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">run</span></span></code></pre></div><p>The script pins Heliodor to commit <code>7ad830fc0f8506c934b61a853ce2eadfa5926b82</code> unless <code>HELIODOR_REF</code> is set.</p><h2 id="acceptance-gate" tabindex="-1">Acceptance gate <a class="header-anchor" href="#acceptance-gate" aria-label="Permalink to &quot;Acceptance gate&quot;">​</a></h2><p>Run the reproducible end-to-end comparison from a clean, committed Celox checkout:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/run-heliodor-bench.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gate</span></span></code></pre></div><p>The gate is deliberately not configurable. It forces all of the following:</p><ul><li>Heliodor commit <code>7ad830fc0f8506c934b61a853ce2eadfa5926b82</code> from the official repository, with a clean checkout;</li><li>benchmark-owned Veryl <code>0.20.2</code>, selected by its exact path and checked with <code>--version</code> rather than taken from <code>PATH</code> or <code>VERYL_BIN</code>;</li><li>a clean, unchanged Celox <code>HEAD</code>, a locked release build in a fresh invocation-owned Cargo target directory, and execution of that exact built binary;</li><li><code>test_soc_linux_boot</code>, runners <code>veryl-cc</code> then <code>celox</code>, and a fixed 300-second timeout for each;</li><li>Celox native backend, <code>O2</code>, two-state mode, full execution, and no SIR pass overrides; and</li><li>separate detached Heliodor worktrees for the two runners so project-local generated files cannot flow from one runner into the other.</li></ul><p>The gate writes a new isolated <code>gate_&lt;timestamp&gt;.&lt;suffix&gt;</code> directory under <code>target/heliodor/results</code>. It accepts exactly two result rows from that invocation. Veryl must exit successfully and log exactly one success for the requested test plus <code>1 passed, 0 failed</code>. Celox must exit successfully and log exactly one native/O2/<code>four_state=false</code>/<code>compile_only=false</code> config record and one full-pass result record. Source manifests, checkout identities, and runner executable hashes are checked before and after execution.</p><p>Subprocess elapsed time is measured with a monotonic nanosecond clock. The gate exits successfully only if both semantic checks pass and the Celox process time is no greater than the Veryl process time. Compile-only completion, a partial window, runner-reported internal time, or process exit zero without the exact markers is a failure. GNU <code>timeout</code> with <code>--kill-after</code> and Python 3 are required.</p><p>Celox has not yet produced a competitive successful full Linux-boot result on this gate. The existence of the command makes the acceptance decision executable; it is not itself evidence that the performance requirement passes.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><p>List available Heliodor <code>#[test]</code> modules:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/run-heliodor-bench.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p>Useful long tests include:</p><table tabindex="0"><thead><tr><th>Test</th><th>Meaning</th></tr></thead><tbody><tr><td><code>test_soc_linux_boot</code></td><td>Linux 5.15 single-hart boot</td></tr><tr><td><code>test_soc_smp_linux_boot_2hart</code></td><td>Linux 5.15 SMP 2-hart boot</td></tr><tr><td><code>test_soc_smp_linux_boot_4hart</code></td><td>Linux 5.15 SMP 4-hart boot</td></tr><tr><td><code>test_soc_linux_boot_71</code></td><td>Linux 7.1 single-hart boot</td></tr><tr><td><code>test_soc_smp_linux_boot_71_2hart</code></td><td>Linux 7.1 SMP 2-hart boot</td></tr><tr><td><code>test_soc_linux_boot_71v</code></td><td>Linux 7.1 vector-enabled boot</td></tr></tbody></table><h2 id="runners" tabindex="-1">Runners <a class="header-anchor" href="#runners" aria-label="Permalink to &quot;Runners&quot;">​</a></h2><p><code>HELIODOR_RUNNERS</code> accepts:</p><table tabindex="0"><thead><tr><th>Runner</th><th>Command</th></tr></thead><tbody><tr><td><code>celox</code></td><td><code>target/release/examples/run_veryl_project_test --project ... --test ...</code></td></tr><tr><td><code>veryl-cc</code></td><td><code>veryl test --ignored --test ... --backend cc</code></td></tr><tr><td><code>veryl-cranelift</code></td><td><code>veryl test --ignored --test ... --backend cranelift</code></td></tr><tr><td><code>veryl-interpret</code></td><td><code>veryl test --ignored --test ... --backend interpret</code></td></tr></tbody></table><p>The Celox runner uses the default Celox backend, which is native x86-64 on x86-64 hosts. Set <code>CELOX_OPT_LEVEL=O0|O1|O2</code> to change optimizer presets.</p><p>Set <code>HELIODOR_TIMEOUT_SEC</code> to override all per-test timeouts. Without a measured Veryl baseline, Linux boot tests use conservative fixed fallbacks such as 300s for single-hart boot, 600s for 2-hart SMP boot, and 1800s for 4-hart SMP boot.</p><p>If <code>veryl</code> is not on <code>PATH</code>, the script installs <code>cargo install veryl --version 0.20.2 --locked</code> into <code>target/heliodor/tools/veryl-0.20.2</code>. Override with <code>VERYL_BIN</code>, <code>HELIODOR_VERYL_VERSION</code>, or set <code>HELIODOR_INSTALL_TOOLS=0</code> to disable automatic installs.</p><h2 id="result-semantics" tabindex="-1">Result semantics <a class="header-anchor" href="#result-semantics" aria-label="Permalink to &quot;Result semantics&quot;">​</a></h2><p><code>target/heliodor/results/results.tsv</code> distinguishes the subprocess exit status from the simulated test result. Its columns are:</p><table tabindex="0"><thead><tr><th>Column</th><th>Meaning</th></tr></thead><tbody><tr><td><code>runner</code></td><td>Runner name</td></tr><tr><td><code>test</code></td><td>Requested Heliodor test</td></tr><tr><td><code>status</code></td><td>Legacy alias of <code>exit_status</code>, retained as the third column for existing readers</td></tr><tr><td><code>elapsed_ns</code></td><td>Full-pass wall time, or <code>NA</code> for every non-pass result</td></tr><tr><td><code>log</code></td><td>Full runner log</td></tr><tr><td><code>semantic_status</code></td><td><code>pass</code>, <code>fail</code>, <code>compile-only</code>, <code>unreported</code>, or <code>invalid</code></td></tr><tr><td><code>exit_status</code></td><td>Subprocess exit status</td></tr><tr><td><code>process_elapsed_ns</code></td><td>Monotonic elapsed time of the subprocess, including failed and compile-only runs</td></tr><tr><td><code>reported_elapsed_ns</code></td><td>Celox runner&#39;s internal elapsed value, or <code>NA</code> when unavailable</td></tr></tbody></table><p>The original <code>runner</code>, <code>test</code>, <code>status</code>, <code>elapsed_ns</code>, and <code>log</code> columns remain in their original positions. A speed result exists only when <code>semantic_status=pass</code>, <code>exit_status=0</code>, and <code>elapsed_ns</code> is numeric. <code>process_elapsed_ns</code> and <code>reported_elapsed_ns</code> are diagnostics and must not be used to claim full-test performance for <code>compile-only</code>, <code>fail</code>, <code>unreported</code>, or <code>invalid</code> rows.</p><p>For Celox, the script requires exactly one complete log line in this form:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CELOX_TEST_RESULT test=&lt;requested-test&gt; status=pass|fail|compile-only elapsed_ns=&lt;integer&gt;</span></span></code></pre></div><p>Malformed, duplicate, missing, wrong-test, mode-inconsistent, or exit-status-inconsistent records cannot become a pass. An intentional <code>HELIODOR_CELOX_COMPILE_ONLY=1</code> run may finish successfully, but its <code>semantic_status</code> is <code>compile-only</code> and its <code>elapsed_ns</code> is <code>NA</code>.</p><p>An existing five-column TSV is migrated atomically on the next run. The script keeps its first copy as <code>results.tsv.v1.bak</code>, recovers Celox semantics from the referenced logs where possible, and marks records without conclusive evidence as <code>unreported</code> or <code>invalid</code>. The migration never promotes process exit zero alone to a Celox full pass.</p><p>The parser/migration and acceptance-gate fixtures run without checking out or executing Heliodor or either compiler:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/tests/run-heliodor-bench-results.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/tests/run-heliodor-bench-gate.sh</span></span></code></pre></div><h2 id="current-caveat" tabindex="-1">Current Caveat <a class="header-anchor" href="#current-caveat" aria-label="Permalink to &quot;Current Caveat&quot;">​</a></h2><p>Celox currently records the semantic result, process result, and wall-clock time for this macro benchmark. Heliodor prints simulated cycle counts with <code>$display</code>; the current Celox detailed test runner suppresses display events, so cycle extraction is only available from Veryl runner logs until display forwarding is exposed in the Celox runner.</p>`,40)])])}const m=t(i,[["render",d]]);export{u as __pageData,m as default};
